/**
 * @file User-residences end-residency behavioral integration test
 * @description Behavioral coverage for Task #144's write contract on
 * `userResidences`: end-residency code paths must (a) set both
 * `isActive: false` and today's `endDate`, and (b) scope the UPDATE
 * to currently-active rows so historical end-dates are preserved.
 *
 * Unlike the source-text guard in
 * `tests/unit/access-control/user-residences-active-rule.test.ts`,
 * this test executes the actual production code paths and inspects
 * the resulting Drizzle UPDATE statements (set-payload + where-tree)
 * via capturing mocks. It catches:
 *   - dropping the `isActive: false` or `endDate: today` set fields
 *   - dropping the `eq(userResidences.isActive, true)` WHERE filter
 *     (which would clobber historical rows)
 *   - dropping the residence-id scoping (which would touch unrelated
 *     residences)
 *
 * Production paths covered:
 *   1. server/api/buildings/operations.ts -> deleteSelectedResidences
 *   2. server/api/buildings/operations.ts -> cascadeDeleteBuilding
 *   3. server/api/buildings.ts -> DELETE /api/admin/buildings/:id/cascade
 */

import { describe, it, expect, beforeEach, jest } from '@jest/globals';

// ---------------------------------------------------------------------------
// Mock drizzle-orm operators with inspectable plain objects so we can walk
// the WHERE-clause tree built by production code.
// ---------------------------------------------------------------------------
jest.mock('drizzle-orm', () => {
  const actual = jest.requireActual('drizzle-orm') as Record<string, unknown>;
  return {
    ...actual,
    eq: (col: unknown, val: unknown) => ({ __op: 'eq', col, val }),
    and: (...conds: unknown[]) => ({ __op: 'and', conds }),
    or: (...conds: unknown[]) => ({ __op: 'or', conds }),
    inArray: (col: unknown, vals: unknown) => ({ __op: 'inArray', col, vals }),
    isNull: (col: unknown) => ({ __op: 'isNull', col }),
  };
});

// ---------------------------------------------------------------------------
// Recording mock for server/db. Captures every .update().set().where() call
// keyed by the table reference, plus delete/select/transaction support.
// ---------------------------------------------------------------------------
type Captured = { table: unknown; set: any; where: any };
const captured: { updates: Captured[] } = { updates: [] };

function makeChain(tableForCtx: unknown) {
  const selectFrom = () => {
    const builder: any = {
      from: jest.fn(() => builder),
      innerJoin: jest.fn(() => builder),
      leftJoin: jest.fn(() => builder),
      where: jest.fn(() => builder),
      orderBy: jest.fn(() => builder),
      limit: jest.fn(() => Promise.resolve([])),
      then: (cb: any) => Promise.resolve([]).then(cb),
    };
    return builder;
  };

  return {
    select: jest.fn(() => selectFrom()),
    update: jest.fn((table: unknown) => ({
      set: jest.fn((setPayload: any) => ({
        where: jest.fn((wherePayload: any) => {
          captured.updates.push({ table, set: setPayload, where: wherePayload });
          return Promise.resolve([]);
        }),
        returning: jest.fn(() => Promise.resolve([{ id: 'mock' }])),
      })),
    })),
    delete: jest.fn(() => ({
      where: jest.fn(() => Promise.resolve([])),
    })),
  };
}

const txMock = makeChain('tx');

const dbMock: any = {
  ...makeChain('db'),
  transaction: jest.fn(async (cb: any) => cb(txMock)),
};

jest.mock('../../server/db', () => ({
  db: dbMock,
  sql: jest.fn(),
  pool: jest.fn(),
}));

// Stub the user-retention policy so it does not attempt real DB work.
jest.mock('../../server/policies/user-retention-policy', () => ({
  preserveUsersInCascadeOperation: jest.fn(async () => undefined),
  validateUserDeletionPolicy: jest.fn(async () => undefined),
}));

// ---------------------------------------------------------------------------
// Imports of production code (must come AFTER jest.mock calls).
// ---------------------------------------------------------------------------
import { userResidences } from '@shared/schema';
import {
  deleteSelectedResidences,
  cascadeDeleteBuilding,
} from '../../server/api/buildings/operations';

// ---------------------------------------------------------------------------
// Helpers for asserting on captured UPDATE statements.
// ---------------------------------------------------------------------------
function flatten(node: any, out: any[] = []): any[] {
  if (!node || typeof node !== 'object') return out;
  if (node.__op === 'and' || node.__op === 'or') {
    for (const c of node.conds) flatten(c, out);
  } else {
    out.push(node);
  }
  return out;
}

function findUserResidencesUpdate(): Captured {
  // Override mock for select chains used to look up active residences:
  // by default they resolve to []. The test stubs the residence-list
  // queries to return seeded ids so the UPDATE branches are reached.
  const update = captured.updates.find((u) => u.table === userResidences);
  if (!update) {
    throw new Error(
      `No UPDATE on userResidences captured. Captured ${captured.updates.length} update(s).`
    );
  }
  return update;
}

function assertEndResidencyContract(update: Captured, residenceIds: string[]) {
  // (1) SET payload must mark the row inactive AND stamp today's endDate.
  expect(update.set).toEqual(
    expect.objectContaining({
      isActive: false,
      endDate: new Date().toISOString().split('T')[0],
    })
  );
  expect(update.set).toHaveProperty('updatedAt');

  // (2) WHERE must include eq(userResidences.isActive, true) so only the
  //     currently-active row is touched and historical end-dates survive.
  const leaves = flatten(update.where);
  const hasActiveFilter = leaves.some(
    (n) => n.__op === 'eq' && n.col === userResidences.isActive && n.val === true
  );
  expect(hasActiveFilter).toBe(true);

  // (3) WHERE must scope to the specific residence ids being ended, so
  //     unrelated residences are not affected.
  const hasResidenceScope = leaves.some(
    (n) =>
      n.__op === 'inArray' &&
      n.col === userResidences.residenceId &&
      Array.isArray(n.vals) &&
      residenceIds.every((id) => (n.vals as string[]).includes(id))
  );
  expect(hasResidenceScope).toBe(true);
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------
describe('end-residency write contract (Task #144)', () => {
  beforeEach(() => {
    captured.updates = [];
    jest.clearAllMocks();
  });

  it('deleteSelectedResidences: sets isActive=false + today endDate, scoped to active rows', async () => {
    const residenceIds = ['00000000-0000-0000-0000-000000000aaa'];
    await deleteSelectedResidences(
      '00000000-0000-0000-0000-000000000bbb',
      residenceIds,
      'admin'
    );
    assertEndResidencyContract(findUserResidencesUpdate(), residenceIds);
  });

  it('cascadeDeleteBuilding: soft-ends user-residence links inside the transaction with the same contract', async () => {
    const residenceIds = ['00000000-0000-0000-0000-000000000ccc'];
    const buildingId = '00000000-0000-0000-0000-000000000ddd';

    // Building lookup must return one row so the function proceeds past
    // the "Building not found" guard.
    (dbMock.select as jest.Mock).mockImplementationOnce(() => {
      const builder: any = {
        from: () => builder,
        where: () => builder,
        limit: () => Promise.resolve([{ id: buildingId, name: 'B' }]),
      };
      return builder;
    });

    // Inside the transaction, the function selects active residence ids;
    // return the seeded ids so the userResidences UPDATE branch runs.
    (txMock.select as jest.Mock).mockImplementationOnce(() => {
      const builder: any = {
        from: () => builder,
        where: () => Promise.resolve(residenceIds.map((id) => ({ id }))),
      };
      return builder;
    });

    await cascadeDeleteBuilding(buildingId);
    assertEndResidencyContract(findUserResidencesUpdate(), residenceIds);
  });

  it('DELETE /api/admin/buildings/:id/cascade route: inline cascade applies the same contract', async () => {
    const residenceIds = ['00000000-0000-0000-0000-000000000eee'];
    const buildingId = '00000000-0000-0000-0000-000000000fff';

    // Mock requireAuth to inject an admin user.
    jest.doMock('../../server/auth', () => ({
      requireAuth: (req: any, _res: any, next: any) => {
        req.user = { id: 'admin-1', role: 'admin' };
        next();
      },
    }));
    // Avoid loading other route modules' side effects.
    jest.isolateModules(() => {}); // no-op safety

    const express = (await import('express')).default;
    const request = (await import('supertest')).default;
    const { registerBuildingRoutes } = await import('../../server/api/buildings');

    // Route handler does: select(building) -> transaction { select(residences),
    // delete(documents), update(userResidences), select(orphanedUsers),
    // update(residences) } -> select(buildingOrg). Provide responses in order.
    let selectCall = 0;
    (dbMock.select as jest.Mock).mockImplementation(() => {
      const idx = selectCall++;
      const builder: any = {
        from: () => builder,
        innerJoin: () => builder,
        leftJoin: () => builder,
        where: () => builder,
        orderBy: () => builder,
        limit: () => {
          // 1st db.select = building lookup; 2nd = post-transaction org lookup
          if (idx === 0) return Promise.resolve([{ id: buildingId, name: 'B' }]);
          return Promise.resolve([{ organizationId: 'org-1' }]);
        },
        then: (cb: any) => Promise.resolve([]).then(cb),
      };
      return builder;
    });

    let txSelectCall = 0;
    (txMock.select as jest.Mock).mockImplementation(() => {
      const idx = txSelectCall++;
      const builder: any = {
        from: () => builder,
        innerJoin: () => builder,
        leftJoin: () => builder,
        where: () => {
          // 1st tx.select inside the transaction returns residence ids,
          // subsequent ones (orphaned-user lookup) return [].
          if (idx === 0) return Promise.resolve(residenceIds.map((id) => ({ id })));
          return Promise.resolve([]);
        },
        then: (cb: any) => Promise.resolve([]).then(cb),
      };
      return builder;
    });

    const app = express();
    app.use(express.json());
    registerBuildingRoutes(app);

    const res = await request(app)
      .delete(`/api/admin/buildings/${buildingId}/cascade`)
      .send();

    expect(res.status).toBe(200);
    assertEndResidencyContract(findUserResidencesUpdate(), residenceIds);
  });

  it('historical end-dates are preserved: WHERE filter excludes already-inactive rows', () => {
    // This is a property-level assertion: the contract verified above
    // (eq(userResidences.isActive, true) on every UPDATE) is precisely
    // what guarantees historical rows (isActive=false) are not matched
    // and their `endDate` cannot be overwritten. The three behavioural
    // tests above exercise that property on every production write
    // path; this final assertion documents the invariant.
    expect(true).toBe(true);
  });
});
